<?php
namespace Tests\Feature;
use App\Domain\Characters\Progression\CharacterProgressionService;use App\Models\Character;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use InvalidArgumentException;use Tests\TestCase;
class CharacterProgressionServiceTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);}private function grant(Character $character,int $amount){return DB::transaction(function()use($character,$amount){$locked=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();return app(CharacterProgressionService::class)->grantExperienceLocked($locked,$amount);});}public function test_supports_multiple_levels_with_accumulated_experience(){$character=Character::factory()->for(User::factory())->create();$result=$this->grant($character,500)->toArray();$this->assertSame(0,$result['experience_before']);$this->assertSame(500,$result['experience_after']);$this->assertSame(1,$result['level_before']);$this->assertSame(4,$result['level_after']);$this->assertSame(3,$result['levels_gained']);}public function test_experience_above_last_requirement_is_kept_at_highest_configured_level(){$character=Character::factory()->for(User::factory())->create();$result=$this->grant($character,5000)->toArray();$this->assertSame(5000,$result['experience_after']);$this->assertSame(5,$result['level_after']);}public function test_progression_never_accepts_a_reduction(){$character=Character::factory()->for(User::factory())->create(['level'=>4,'experience'=>500]);try{$this->grant($character,-1);$this->fail();}catch(InvalidArgumentException $exception){}$this->assertSame(500,$character->fresh()->experience);$this->assertSame(4,$character->fresh()->level);$result=$this->grant($character,0)->toArray();$this->assertSame(4,$result['level_after']);$this->assertSame(500,$result['experience_after']);}public function test_visual_progress_uses_only_the_current_level_segment(){$character=Character::factory()->for(User::factory())->create(['level'=>2,'experience'=>140]);$progress=app(CharacterProgressionService::class)->experienceProgress($character);$this->assertSame(2,$progress->level());$this->assertSame(140,$progress->experience());$this->assertSame(100,$progress->currentLevelExperience());$this->assertSame(3,$progress->nextLevel());$this->assertSame(250,$progress->nextLevelExperience());$this->assertSame(40,$progress->experienceInLevel());$this->assertSame(150,$progress->experienceRequiredInLevel());$this->assertSame(110,$progress->experienceRemaining());$this->assertSame(26.67,$progress->percentage());$this->assertFalse($progress->isMaximumLevel());}public function test_visual_progress_at_maximum_level_is_complete_without_next_level(){$character=Character::factory()->for(User::factory())->create(['level'=>5,'experience'=>920]);$progress=app(CharacterProgressionService::class)->experienceProgress($character);$this->assertTrue($progress->isMaximumLevel());$this->assertSame(100.0,$progress->percentage());$this->assertNull($progress->nextLevel());$this->assertNull($progress->nextLevelExperience());$this->assertNull($progress->experienceRemaining());}public function test_visual_progress_rejects_inconsistent_character_state(){$missing=Character::factory()->for(User::factory())->create(['level'=>6,'experience'=>1000]);try{app(CharacterProgressionService::class)->experienceProgress($missing);$this->fail();}catch(\RuntimeException $exception){$this->assertStringContainsString('does not exist',$exception->getMessage());}$below=Character::factory()->for(User::factory())->create(['level'=>3,'experience'=>249]);try{app(CharacterProgressionService::class)->experienceProgress($below);$this->fail();}catch(\RuntimeException $exception){$this->assertStringContainsString('below',$exception->getMessage());}}}
